Set-StrictMode -Version 2.0
function Invoke-GodModeCodexRouter { param([string]$Project='.') $r=Initialize-GodModeStructure $Project; $c=Get-Command codex -ErrorAction SilentlyContinue|select -First 1; $ver=$null;$exec=$false;$json=$false;$schema=$false;$app=$false; if($c){ try{$v=Invoke-GodModeNativeCommand $c.Source @('--version') (Resolve-GodModeProjectPath $Project) 8; if($v.exit_code -eq 0){$ver=($v.stdout+$v.stderr).Trim()}}catch{}; try{$h=Invoke-GodModeNativeCommand $c.Source @('exec','--help') (Resolve-GodModeProjectPath $Project) 8; $txt=$h.stdout+$h.stderr; if($h.exit_code -eq 0){$exec=$true}; if($txt -match '--json'){$json=$true}; if($txt -match '--output-schema'){$schema=$true}}catch{}; try{$a=Invoke-GodModeNativeCommand $c.Source @('app-server','--help') (Resolve-GodModeProjectPath $Project) 8; if($a.exit_code -eq 0){$app=$true}}catch{} }; $router=@{schema_version=1;generated_at=Get-GodModeIso;codex_app_installed='unknown';codex_app_version=$null;codex_cli_installed=[bool]$c;codex_cli_path=if($c){$c.Source}else{$null};codex_cli_version=$ver;codex_command_executes=[bool]$ver;codex_exec_exists=$exec;codex_exec_json_available=$json;codex_exec_output_schema_available=$schema;codex_exec_readonly_probe='not_run_to_avoid_worker_call';codex_app_server_exists=$app;project_trusted='unknown';current_surface='codex_app_or_cli_unknown';structured_worker_route=if($exec -and $schema){'codex_exec_output_schema'}elseif($exec){'codex_exec_manual_schema'}else{'dry_run_agent_skeleton'};visual_browser_route='reality_router';degraded_reasons=@();blockers=@()}; if(-not $exec){$router.degraded_reasons+='codex_exec_not_verified'}; Write-GodModeJsonAtomic (Join-GodModePath $r 'state/codex-router.json') $router|Out-Null; $router }
